  ('public-health-specialist-moex-01267', 'public-health-specialist', 'public-health-specialist-moex-111-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於群體免疫（herd immunity）的敘述，下列何者正確？①施打疫苗或是自然感染都可能造', '["群體免疫的保護對象是已經具有免疫力者，不包括本身還沒有免疫力的人", "如果某傳染病打疫苗或感染後之免疫力會隨時間下降，群體免疫的效果將會隨時間減弱", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:58+00:00", "source_pdf_sha1": "6407aa1bde53", "answer_pdf_sha1": "99abb9d811bf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01268', 'public-health-specialist', 'public-health-specialist-moex-111-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '小明是個健康新聞愛好者。下列是他看了新聞之後作的推論，請問何者犯了生態謬誤 （ecologicalfallacy）？', '["跨國研究發現每年紅酒消費量高的國家有較低的心血管疾病率。小明推論紅酒攝取可降低 心血管疾病風險", "某臨床試驗針對100名受試者進行研究，發現某高血壓新藥的療效比舊藥好。小明推論全 國高血壓病患都該換用新藥控制血壓", "英國研究發現汽油業工人抽菸與肺癌的關係。小明於是推論所有人抽菸都會增高肺癌風險", "世界衛生組織發現紅肉攝取量多的人有較高的大腸直腸癌風險。小明推論紅肉生產國的大 腸直腸癌疾病率會比非紅肉生產國高"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:58+00:00", "source_pdf_sha1": "6407aa1bde53", "answer_pdf_sha1": "99abb9d811bf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01269', 'public-health-specialist', 'public-health-specialist-moex-111-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', 'Hill’scriteriaforcausation中何者是流行病學家認為必要的標準？', '["關聯強度（strengthofassociation）", "時序性（temporality）", "一致性（consistency）", "生物梯度（biologicalgradient）或劑量反應關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:58+00:00", "source_pdf_sha1": "6407aa1bde53", "answer_pdf_sha1": "99abb9d811bf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01270', 'public-health-specialist', 'public-health-specialist-moex-111-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '下列關於疾病自然史與三段五級預防的敘述，何者錯誤？', '["春天花粉過多的季節戴口罩來減少花粉過敏是屬於健康促進的行為", "衛生教育是藉由改變個人的易感受性促進宿主健康", "實施預防注射為特殊保護，用來減少或避免該疾病的發生", "療養院的長期照護屬於末段預防"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:58+00:00", "source_pdf_sha1": "6407aa1bde53", "answer_pdf_sha1": "99abb9d811bf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01271', 'public-health-specialist', 'public-health-specialist-moex-111-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '有關臨床試驗設計，下列何者錯誤？', '["常會有一組病人被分派到使用安慰劑，來避免安慰劑效應", "常會進行隨機分派來確保治療組與非治療組之間的可比較性", "常會透過病人配對來確保治療組與非治療組之間的可比較性", "常會使用雙盲或是三盲來減少偏誤（bias）的產生"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:58+00:00", "source_pdf_sha1": "6407aa1bde53", "answer_pdf_sha1": "99abb9d811bf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01272', 'public-health-specialist', 'public-health-specialist-moex-111-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於病例對照研究的配對設計，下列何者正確？', '["配對設計有可能增加該研究的效能（efficiency），提高估計的精確度（precision）", "配對完成之後，分析時就不需要考慮或納入配對因子", "配對設計本身可以完全避免因為配對因子所帶來的干擾（confounding）", "原理及分析方式與世代研究之配對設計相同"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:58+00:00", "source_pdf_sha1": "6407aa1bde53", "answer_pdf_sha1": "99abb9d811bf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01273', 'public-health-specialist', 'public-health-specialist-moex-111-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '下列那一種情形，勝算比（oddsratio）最不適合用來估計危險比（riskratio）？', '["當疾病為稀有疾病且效應值（effectsize）很小", "當疾病為稀有疾病且效應值（effectsize）較大", "當疾病不屬於稀有疾病且效應值（effectsize）很小", "當疾病不屬於稀有疾病且效應值（effectsize）很大"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:58+00:00", "source_pdf_sha1": "6407aa1bde53", "answer_pdf_sha1": "99abb9d811bf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01274', 'public-health-specialist', 'public-health-specialist-moex-111-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '在一世代研究中探討攝取綜合維生素與糖尿病風險時，使用存活分析會將追蹤頭幾年的人年 排除，主要是為避免下列何種偏誤（bias）？', '["因為糖尿病相關的危險因子可能在高綜合維生素攝取與低綜合維生素攝取兩組中的分布不同", "有早期糖尿病症狀但還未被診斷有糖尿病的受試者可能開始改變飲食", "那些有服用綜合維生素的受試者可能會因為較常就醫而容易被診斷出有糖尿病", "不可被重複的隨機研究發現"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:58+00:00", "source_pdf_sha1": "6407aa1bde53", "answer_pdf_sha1": "99abb9d811bf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
